            balanceText = format(balance: balance)
            recentTransactions = try await processor.recentTransactions(for: accountId, limit: 10)
            errorMessage = nil
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    private func format(balance: AccountBalance) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = balance.currencyCode
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = balance.available as NSDecimalNumber
        return formatter.string(from: number) ?? "\(balance.currencyCode) \(balance.available)"
